import React, { useState } from "react";
import InstructionBox from "../InstructionBox";
import "../../styles/modes.css";

const VisualEquivalence = () => {
  const [currentLevel, setCurrentLevel] = useState(0);

  const equivalences = [
    {
      title: "Halves to Fourths",
      left: { numerator: 1, denominator: 2, label: "1/2", color: "#6366F1" },
      right: { numerator: 2, denominator: 4, label: "2/4", color: "#6366F1" },
      message: "1/2 = 2/4 ✨",
      explanation: "Cut each piece in HALF → 1 piece becomes 2 pieces!"
    },
    {
      title: "Halves to Eighths",
      left: { numerator: 1, denominator: 2, label: "1/2", color: "#10B981" },
      right: { numerator: 4, denominator: 8, label: "4/8", color: "#10B981" },
      message: "1/2 = 4/8 ✨",
      explanation: "Cut each piece into 4 parts → 1 piece becomes 4 pieces!"
    },
    {
      title: "Thirds to Sixths",
      left: { numerator: 1, denominator: 3, label: "1/3", color: "#EF4444" },
      right: { numerator: 2, denominator: 6, label: "2/6", color: "#EF4444" },
      message: "1/3 = 2/6 ✨",
      explanation: "Cut each piece in HALF → 1 piece becomes 2 pieces!"
    },
    {
      title: "Two-Thirds to Sixths",
      left: { numerator: 2, denominator: 3, label: "2/3", color: "#F59E0B" },
      right: { numerator: 4, denominator: 6, label: "4/6", color: "#F59E0B" },
      message: "2/3 = 4/6 ✨",
      explanation: "Cut each piece in HALF → 2 pieces become 4 pieces!"
    },
    {
      title: "Fourths to Eighths",
      left: { numerator: 1, denominator: 4, label: "1/4", color: "#8B5CF6" },
      right: { numerator: 2, denominator: 8, label: "2/8", color: "#8B5CF6" },
      message: "1/4 = 2/8 ✨",
      explanation: "Cut each piece in HALF → 1 piece becomes 2 pieces!"
    },
  ];

  const level = equivalences[currentLevel];

  const renderBar = (numerator, denominator, color) => {
    const percentage = (numerator / denominator) * 100;
    return (
      <div style={{ width: "100%", marginBottom: "8px" }}>
        <div
          style={{
            display: "flex",
            height: "60px",
            borderRadius: "8px",
            overflow: "hidden",
            boxShadow: "0 4px 8px rgba(0,0,0,0.1)",
            backgroundColor: "#E5E7EB",
          }}
        >
          <div
            style={{
              width: `${percentage}%`,
              backgroundColor: color,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "white",
              fontWeight: "700",
              fontSize: "1.1rem",
              transition: "all 0.3s ease",
            }}
          >
            {percentage > 20 && numerator}
          </div>
        </div>
      </div>
    );
  };

  const nextLevel = () => {
    if (currentLevel < equivalences.length - 1) {
      setCurrentLevel(currentLevel + 1);
    }
  };

  const prevLevel = () => {
    if (currentLevel > 0) {
      setCurrentLevel(currentLevel - 1);
    }
  };

  return (
    <div className="mode-container">
      <InstructionBox
        title="Visual Equivalence"
        description="Different fractions can show the SAME amount! 🤯"
      />

      <div className="equivalence-display-bars">
        <div className="equivalence-bars-container">
          <div className="bar-column">
            <div className="fraction-label-bar">{level.left.label}</div>
            {renderBar(level.left.numerator, level.left.denominator, level.left.color)}
          </div>

          <div className="equals-sign-bars">=</div>

          <div className="bar-column">
            <div className="fraction-label-bar">{level.right.label}</div>
            {renderBar(level.right.numerator, level.right.denominator, level.right.color)}
          </div>
        </div>
      </div>

      <div className="equivalence-message">
        <h2 style={{ fontSize: "2rem", color: level.left.color }}>
          {level.message}
        </h2>
        <p style={{ fontSize: "1.1rem", color: "#6B7280", marginTop: "12px" }}>
          Look! The <strong>colored part is exactly the same size</strong> in both bars. Even though the numbers are different, they show the SAME amount! 🎯
        </p>
        <p style={{ fontSize: "1.1rem", color: level.left.color, marginTop: "16px", fontWeight: "700", backgroundColor: "rgba(255,255,255,0.7)", padding: "12px", borderRadius: "8px" }}>
          💡 {level.explanation}
        </p>
      </div>

      <div className="level-progress">
        <span style={{ fontSize: "1.1rem", fontWeight: "700" }}>
          Level {currentLevel + 1} of {equivalences.length}
        </span>
        <div className="progress-bar">
          <div
            className="progress-fill"
            style={{ width: `${((currentLevel + 1) / equivalences.length) * 100}%` }}
          />
        </div>
      </div>

      <div className="button-group">
        <button
          onClick={prevLevel}
          disabled={currentLevel === 0}
          className="btn-modern-primary"
          style={{ opacity: currentLevel === 0 ? 0.5 : 1 }}
        >
          ← Previous
        </button>
        <button onClick={nextLevel} disabled={currentLevel === equivalences.length - 1} className="btn-modern-primary" style={{ opacity: currentLevel === equivalences.length - 1 ? 0.5 : 1 }}>
          Next →
        </button>
      </div>

      {currentLevel === equivalences.length - 1 && (
        <div className="message-box">
          <h3 style={{ color: "#10B981", fontSize: "1.5rem" }}>
            🎉 You learned equivalence!
          </h3>
          <p>When you cut pieces smaller, you get more pieces, but the colored part stays the SAME!</p>
        </div>
      )}
    </div>
  );
};

export default VisualEquivalence;
